// login.ts - MODIFICHE
import { Component, inject } from '@angular/core';
import { FormBuilder, FormGroup, Validators, ReactiveFormsModule } from '@angular/forms';
import { Router, RouterLink } from '@angular/router';
import { CommonModule } from '@angular/common';
import { AuthService } from '../../services/Base/auth.service';
import { environment } from '../../../environments/environment';
import { SupabaseService } from '../../services/Base/supabase.service'; // AGGIUNGI
import { LucideAngularModule } from 'lucide-angular';

@Component({
  selector: 'app-login',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule, RouterLink, LucideAngularModule],
  templateUrl: './login.html',
  styleUrls: ['./login.css']
})
export class Login {
  private fb = inject(FormBuilder);
  private authService = inject(AuthService);
  private router = inject(Router);
  private supabaseService = inject(SupabaseService); // AGGIUNGI

  loginForm: FormGroup;
  isLoading = false;
  errorMessage = '';
  showPassword = false;

  constructor() {
    this.loginForm = this.fb.group({
      email: ['', [Validators.required, Validators.email]],
      password: ['', [Validators.required, Validators.minLength(6)]],
      rememberMe: [false]
    });

    if (!this.isProduction) {
      this.prefillDemoCredentials();
    }
  }

  async onSubmit() {
    if (this.loginForm.invalid) {
      this.markFormGroupTouched();
      return;
    }

    this.isLoading = true;
    this.errorMessage = '';

    const { email, password, rememberMe } = this.loginForm.value;

    try {
      const result = await this.authService.login(email, password, rememberMe);
      
      if (result.error) {
        const errorMessage = result.error instanceof Error ? result.error.message : String(result.error);
        this.errorMessage = this.getErrorMessage(errorMessage);
      } else if (result.data?.user) {
        console.log('✅ Login effettuato con successo');
        
        // 🔥 RIMUOVI la chiamata a checkStaffMembership - non è necessaria
        // await this.checkStaffMembership(email);
        
        // MESSAGGIO DI SUCCESSO CON CONTESTO
        const currentContext = this.authService.getCurrentContext();
        const contextNames = {
          'staff': 'Dipendente',
          'supplier': 'Fornitore', 
          'customer': 'Cliente'
        };
        
        this.errorMessage = `Accesso effettuato come ${contextNames[currentContext]}! Reindirizzamento...`;
        
        // BREVE PAUSA PER MOSTRARE IL MESSAGGIO
        setTimeout(() => {
          this.navigateBasedOnContext();
        }, 1000);
      }
    } catch (error: any) {
      console.error('Login error:', error);
      this.errorMessage = 'Errore durante il login. Riprova più tardi.';
    } finally {
      this.isLoading = false;
    }
  }


  // METODO PER VERIFICARE SE L'UTENTE È STAFF
  private async checkStaffMembership(email: string) {
    try {
      // 🔥 CORREZIONE: Rimuovi is_active dalla query
      const { data: staffRecords, error } = await this.supabaseService.getSupabaseClient()
        .from('restaurant_staff')
        .select('*')
        .eq('email', email.toLowerCase())
        .in('invitation_status', ['accepted', 'pending']); // ⚠️ RIMOSSO is_active

      if (staffRecords && staffRecords.length > 0) {
        console.log('🎯 Utente trovato come staff member:', staffRecords);
      } else {
        console.log('ℹ️ Utente non è staff member');
      }
    } catch (error) {
      console.log('ℹ️ Errore nel controllo staff membership:', error);
    }
  }


  // METODO PER NAVIGARE IN BASE AL CONTESTO
  private navigateBasedOnContext() {
    const context = this.authService.getCurrentContext();
    
    switch (context) {
      case 'staff':
        this.router.navigate(['/restaurant/dashboard']);
        break;
      case 'supplier':
        this.router.navigate(['/supplier/dashboard']);
        break;
      case 'customer':
      default:
        this.router.navigate(['/customer']);
        break;
    }
  }

  togglePasswordVisibility() {
    this.showPassword = !this.showPassword;
  }

  private markFormGroupTouched() {
    Object.keys(this.loginForm.controls).forEach(key => {
      const control = this.loginForm.get(key);
      control?.markAsTouched();
    });
  }

  private getErrorMessage(error: string): string {
    const errorMap: { [key: string]: string } = {
      'Invalid login credentials': 'Email o password non validi.',
      'Email not confirmed': 'Email non confermata. Controlla la tua casella di posta.',
      'Invalid email': 'Email non valida.',
      'Network error': 'Errore di rete. Controlla la tua connessione.',
      'Email rate limit exceeded': 'Troppi tentativi. Riprova più tardi.'
    };
    
    return errorMap[error] || `Errore: ${error}`;
  }

  private prefillDemoCredentials() {
    console.log('Modalità sviluppo: credenziali demo disponibili');
  }

  useDemoCredentials(role: 'restaurant' | 'customer') {
    if (role === 'restaurant') {
      this.loginForm.patchValue({
        email: 'ristorante@demo.com',
        password: 'demodemo'
      });
    } else {
      this.loginForm.patchValue({
        email: 'cliente@demo.com',
        password: 'demodemo'
      });
    }
  }

  get email() { return this.loginForm.get('email'); }
  get password() { return this.loginForm.get('password'); }

  get isProduction(): boolean {
    return environment.production;
  }
}